mapper.select:
SELECT j.*, c.name AS company_name FROM jobs j LEFT JOIN companies c ON j.company_id = c.id WHERE j.status = 'OPEN'
AND (j.title LIKE CONCAT('%', #{keyword}, '%') OR c.name LIKE CONCAT('%', #{keyword}, '%'))
AND j.location LIKE CONCAT('%', #{location}, '%')
AND j.job_type = #{jobType}
ORDER BY j.posted_at DESC LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE jobs
title = #{title}, description = #{description}, requirement = #{requirement}, salary_range = #{salaryRange}, location = #{location}, job_type = #{jobType}, status = #{status}, deadline = #{deadline},
WHERE id = #{id}
